mapper.select:
SELECT MAX(seq_no)
FROM chat_message
WHERE session_id = #{sessionId}

SELECT MIN(turn_seq)
FROM chat_message
WHERE session_id = #{sessionId}
  AND turn_id = #{turnId}
  AND turn_seq IS NOT NULL

mapper.delete:
DELETE FROM chat_message
WHERE session_id = #{sessionId}
  AND turn_id = #{turnId}
  AND role IN

      #{role}

mapper.update:
UPDATE chat_message
SET turn_completed = TRUE,
    updated_at = NOW()
WHERE session_id = #{sessionId}
  AND turn_id = #{turnId}
